import{_ as a,o as r,c as e,ag as d}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Subscription Plans","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/subscriptions.md","filePath":"getting-started/subscriptions.md"}'),n={name:"getting-started/subscriptions.md"};function o(i,t,s,l,c,p){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="subscription-plans" tabindex="-1">Subscription Plans <a class="header-anchor" href="#subscription-plans" aria-label="Permalink to &quot;Subscription Plans&quot;">​</a></h1><p>Diamond Analytics offers three subscription tiers.</p><h2 id="plan-comparison" tabindex="-1">Plan Comparison <a class="header-anchor" href="#plan-comparison" aria-label="Permalink to &quot;Plan Comparison&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Player</th><th>Coach</th><th>Organization</th></tr></thead><tbody><tr><td>Price</td><td>$3.99/mo or $34.99/yr</td><td>$12.99/mo or $99.99/yr</td><td>$24.99/mo or $199.99/yr</td></tr><tr><td>Players</td><td>Up to 5</td><td>Unlimited</td><td>Unlimited</td></tr><tr><td>Teams</td><td>—</td><td>1</td><td>Up to 5</td></tr><tr><td>Full analytics</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Training suggestions</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Player report cards</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Team analytics</td><td>—</td><td>✅</td><td>✅</td></tr><tr><td>Lineup builders</td><td>—</td><td>✅</td><td>✅</td></tr><tr><td>Multi-user (coaches, parents)</td><td>—</td><td>✅</td><td>✅</td></tr><tr><td>AI coach notes</td><td>—</td><td>50/mo</td><td>200/mo</td></tr><tr><td>Voice logging</td><td>100/mo</td><td>500/mo</td><td>2000/mo</td></tr><tr><td>Free trial</td><td>—</td><td>30 days</td><td>30 days</td></tr></tbody></table><h2 id="player-plan" tabindex="-1">Player Plan <a class="header-anchor" href="#player-plan" aria-label="Permalink to &quot;Player Plan&quot;">​</a></h2><p>Designed for parents tracking their own child&#39;s development. Up to 5 player profiles with full analytics, training suggestions, and report cards. No team features — if your coach uses Diamond Analytics their team subscription covers team-level access.</p><h2 id="coach-plan" tabindex="-1">Coach Plan <a class="header-anchor" href="#coach-plan" aria-label="Permalink to &quot;Coach Plan&quot;">​</a></h2><p>The most popular plan for travel and recreational team coaches. One team with unlimited players, full analytics, lineup builders, and multi-user access so assistant coaches and scorekeeping parents can contribute.</p><h2 id="organization-plan" tabindex="-1">Organization Plan <a class="header-anchor" href="#organization-plan" aria-label="Permalink to &quot;Organization Plan&quot;">​</a></h2><p>For club directors and organizations managing multiple teams. Up to 5 teams under one subscription with cross-team analytics and organization-level dashboard.</p><h2 id="managing-your-subscription" tabindex="-1">Managing Your Subscription <a class="header-anchor" href="#managing-your-subscription" aria-label="Permalink to &quot;Managing Your Subscription&quot;">​</a></h2><p>Access subscription management through <strong>Settings → Manage Subscription</strong>. You can upgrade, downgrade, update your payment method, or cancel at any time through the Stripe Customer Portal.</p>',12)])])}const m=a(n,[["render",o]]);export{h as __pageData,m as default};
